1	`include "common_defs.v"
2	
3	module sync_short (
4	    input clock,
5	    input reset,
6	    input enable,
7	
8	    input set_stb,
9	    input [7:0] set_addr,
10	    input [31:0] set_data,
11	
12	    input [31:0] sample_in,
13	    input sample_in_strobe,
14	
15	    output reg short_preamble_detected,
16	
17	    input [31:0] phase_out,
18	    input phase_out_stb,
19	
20	    output [31:0] phase_in_i,
21	    output [31:0] phase_in_q,
22	    output phase_in_stb,
23	
24	    output reg signed [31:0] phase_offset
25	);
26	`include "common_params.v"
27	
28	localparam WINDOW_SHIFT = 4;
29	localparam DELAY_SHIFT = 4;
30	
31	wire [31:0] mag_sq;
32	wire mag_sq_stb;
33	
34	wire [31:0] mag_sq_avg;
35	wire mag_sq_avg_stb;
36	reg [31:0] prod_thres;
37	
38	wire [31:0] sample_delayed;
39	wire sample_delayed_stb;
40	
41	reg [31:0] sample_delayed_conj;
42	reg sample_delayed_conj_stb;
43	
44	wire [63:0] prod;
45	wire prod_stb;
46	
47	reg [15:0] delay_i;
48	reg [15:0] delay_q_neg;
49	
50	wire [63:0] prod_avg;
51	wire prod_avg_stb;
52	
53	wire [31:0] freq_offset_i;
54	wire [31:0] freq_offset_q;
55	wire freq_offset_stb;
56	
57	reg [31:0] phase_out_neg;
58	
59	wire [31:0] delay_prod_avg_mag;
60	wire delay_prod_avg_mag_stb;
61	
62	reg [31:0] plateau_count;
63	
64	// this is to ensure that the short preambles contains both positive and
65	// negative in-phase, to avoid raise false positives when there is a constant
66	// power
67	reg [31:0] pos_count;
68	reg [31:0] min_pos;
69	reg has_pos;
70	reg [31:0] neg_count;
71	reg [31:0] min_neg;
72	reg has_neg;
73	
74	wire [31:0] min_plateau;
75	
76	// minimal number of samples that has to exceed plateau threshold to claim
77	// a short preamble
78	setting_reg #(.my_addr(SR_MIN_PLATEAU), .width(32), .at_reset(100)) sr_0 (
79	    .clk(clock), .rst(reset), .strobe(set_stb), .addr(set_addr), .in(set_data),
80	    .out(min_plateau), .changed());
81	
82	
83	complex_to_mag_sq mag_sq_inst (
84	    .clock(clock),
85	    .enable(enable),
86	    .reset(reset),
87	
88	    .i(sample_in[31:16]),
89	    .q(sample_in[15:0]),
90	    .input_strobe(sample_in_strobe),
91	
92	    .mag_sq(mag_sq),
93	    .mag_sq_strobe(mag_sq_stb)
94	);
95	
96	moving_avg #(.DATA_WIDTH(32), .WINDOW_SHIFT(WINDOW_SHIFT)) mag_sq_avg_inst (
97	    .clock(clock),
98	    .enable(enable),
99	    .reset(reset),
100	
101	    .data_in(mag_sq),
102	    .input_strobe(mag_sq_stb),
103	    .data_out(mag_sq_avg),
104	    .output_strobe(mag_sq_avg_stb)
105	);
106	
107	delay_sample #(.DATA_WIDTH(32), .DELAY_SHIFT(DELAY_SHIFT)) sample_delayed_inst (
108	    .clock(clock),
109	    .enable(enable),
110	    .reset(reset),
111	
112	    .data_in(sample_in),
113	    .input_strobe(sample_in_strobe),
114	    .data_out(sample_delayed),
115	    .output_strobe(sample_delayed_stb)
116	);
117	
118	complex_mult delay_prod_inst (
119	    .clock(clock),
120	    .enable(enable),
121	    .reset(reset),
122	
123	    .a_i(sample_in[31:16]),
124	    .a_q(sample_in[15:0]),
125	    .b_i(sample_delayed_conj[31:16]),
126	    .b_q(sample_delayed_conj[15:0]),
127	    .input_strobe(sample_delayed_conj_stb),
128	
129	    .p_i(prod[63:32]),
130	    .p_q(prod[31:0]),
131	    .output_strobe(prod_stb)
132	);
133	
134	moving_avg #(.DATA_WIDTH(32), .WINDOW_SHIFT(WINDOW_SHIFT))
135	delay_prod_avg_i_inst (
136	    .clock(clock),
137	    .enable(enable),
138	    .reset(reset),
139	    .data_in(prod[63:32]),
140	    .input_strobe(prod_stb),
141	    .data_out(prod_avg[63:32]),
142	    .output_strobe(prod_avg_stb)
143	);
144	
145	moving_avg #(.DATA_WIDTH(32), .WINDOW_SHIFT(WINDOW_SHIFT)) 
146	delay_prod_avg_q_inst (
147	    .clock(clock),
148	    .enable(enable),
149	    .reset(reset),
150	    .data_in(prod[31:0]),
151	    .input_strobe(prod_stb),
152	    .data_out(prod_avg[31:0])
153	);
154	
155	
156	// for fixing freq offset
157	moving_avg #(.DATA_WIDTH(32), .WINDOW_SHIFT(6))
158	freq_offset_i_inst (
159	    .clock(clock),
160	    .enable(enable),
161	    .reset(reset),
162	    .data_in(prod[63:32]),
163	    .input_strobe(prod_stb),
164	    .data_out(phase_in_i),
165	    .output_strobe(phase_in_stb)
166	);
167	
168	moving_avg #(.DATA_WIDTH(32), .WINDOW_SHIFT(6)) 
169	freq_offset_q_inst (
170	    .clock(clock),
171	    .enable(enable),
172	    .reset(reset),
173	    .data_in(prod[31:0]),
174	    .input_strobe(prod_stb),
175	    .data_out(phase_in_q)
176	);
177	
178	complex_to_mag #(.DATA_WIDTH(32)) delay_prod_avg_mag_inst (
179	    .clock(clock),
180	    .reset(reset),
181	    .enable(enable),
182	
183	    .i(prod_avg[63:32]),
184	    .q(prod_avg[31:0]),
185	    .input_strobe(prod_avg_stb),
186	    .mag(delay_prod_avg_mag),
187	    .mag_stb(delay_prod_avg_mag_stb)
188	);
189	
190	always @(posedge clock) begin
191	    if (reset) begin
192	        sample_delayed_conj <= 0;
193	        sample_delayed_conj_stb <= 0;
194	
